import{_ as r,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"机械长刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/机械长刀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/机械长刀.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/机械长刀.md"};function p(l,a,_,i,b,c){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"机械长刀",tabindex:"-1"},[n("机械长刀 "),e("a",{class:"header-anchor",href:"#机械长刀","aria-label":'Permalink to "机械长刀"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),o('<h1 id="机械长刀-1" tabindex="-1">机械长刀 <a class="header-anchor" href="#机械长刀-1" aria-label="Permalink to &quot;机械长刀&quot;">​</a></h1><p>机械长刀<br> 机械长刀<br> 科技本质<br> D+500<br> 体积3<br> 这是一把充满科技气息的长刀，刀身轻薄微曲，单刃，仔细看可以看到刀背上的电路装置。</p><p>【特殊武装】刀柄结构类似自行车，带有扳机。扣下扳机会像手枪一样顺着刀刃指向的方向发射子弹。<br> 使用枪部分进行攻击时，会带给对手D级来源的措手不及<br> 刀 伤害6L 破甲2<br> 枪 伤害6L 高速5 短点射 装弹数11</p><p>【能量体运用】使用时按下像是自行车手刹的东西，便会将装载进刀柄的能量模块发挥效用，使刀刃和子弹附带对应效果，一开始并不会自己装载模块。</p><p>能量块<br> 500<br> 根据购买时选择两种能量攻击形式，同样的，一种能量攻击形式绑定一个攻击模式。例如：刀（火焰能量）枪（冰冻能量）。<br> ps：禁止在同攻击模式下声明使用不是该模式下的能量攻击。例如：刀（火焰）打出冰冻伤害效果。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
